// ── Inline: drift-check (buildDriftReport) ────────────────────────────
function normalizeNode(n) {
  return { name: n.name, type: n.type, typeVersion: n.typeVersion, parameters: n.parameters || {} };
}
function nodeMap(nodes) {
  const m = new Map();
  for (const n of nodes) m.set(n.name + '|' + n.type, normalizeNode(n));
  return m;
}
function liveIdSet(liveWfs) {
  return new Set(liveWfs.map(function(w) { return w.id; }).filter(Boolean));
}
function matchByName(rWf, liveWfs) {
  return liveWfs.find(function(lw) { return lw.name.trim() === rWf.name.trim(); }) || null;
}
function diffNodes(wfName, rNodes, lNodes) {
  const drifts = [];
  const rMap = nodeMap(rNodes), lMap = nodeMap(lNodes);
  for (const [k, n] of rMap) {
    if (!lMap.has(k)) drifts.push({ type: 'MISSING_NODE', workflowName: wfName, message: 'Node "' + n.name + '" (' + n.type + ') im Repo vorhanden, fehlt auf Mini', severity: 'critical' });
  }
  for (const [k, n] of lMap) {
    if (!rMap.has(k)) drifts.push({ type: 'EXTRA_NODE', workflowName: wfName, message: 'Node "' + n.name + '" (' + n.type + ') auf Mini vorhanden, nicht im Repo', severity: 'warning' });
  }
  return drifts;
}
function checkWebhooks(wfName, rNodes, lNodes) {
  const drifts = [];
  const rMap = nodeMap(rNodes), lMap = nodeMap(lNodes);
  for (const [k, rn] of rMap) {
    if (rn.type !== 'n8n-nodes-base.webhook') continue;
    const ln = lMap.get(k);
    if (!ln) continue;
    const rm = rn.parameters && rn.parameters.httpMethod;
    const lm = ln.parameters && ln.parameters.httpMethod;
    if (rm && lm && rm !== lm) drifts.push({ type: 'WEBHOOK_METHOD_CHANGED', workflowName: wfName, message: 'Webhook "' + rn.name + '": Repo=' + rm + ', Mini=' + lm, severity: 'critical' });
  }
  return drifts;
}
function checkExecRefs(wfName, lNodes, liveIds, pgwId) {
  const drifts = [];
  for (const n of lNodes) {
    if (n.type !== 'n8n-nodes-base.executeWorkflow') continue;
    const refId = n.parameters && n.parameters.workflowId && n.parameters.workflowId.value;
    if (!refId) continue;
    if (!liveIds.has(refId)) drifts.push({ type: 'DEAD_EXECUTE_WORKFLOW_REF', workflowName: wfName, message: 'Node "' + n.name + '" referenziert Workflow-ID "' + refId + '" — existiert nicht auf Mini', severity: 'critical' });
    if (n.name.toLowerCase().indexOf('pgw') !== -1 && refId !== pgwId) drifts.push({ type: 'WRONG_PGW_ID', workflowName: wfName, message: 'Node "' + n.name + '" zeigt auf PGW-ID "' + refId + '", erwartet "' + pgwId + '"', severity: 'critical' });
  }
  return drifts;
}
function checkStockMovementPath(wfName, lNodes, pgwId) {
  var hasPrep = lNodes.some(function(n) { return n.name === 'Prepare PGW - stock_movement' && n.type === 'n8n-nodes-base.code'; });
  var hasExec = lNodes.some(function(n) { return n.name === 'WF-PGW - stock_movement' && n.type === 'n8n-nodes-base.executeWorkflow' && n.parameters && n.parameters.workflowId && n.parameters.workflowId.value === pgwId; });
  if (hasPrep && hasExec) return [];
  var missing = [];
  if (!hasPrep) missing.push('"Prepare PGW - stock_movement" (Code-Node)');
  if (!hasExec) missing.push('"WF-PGW - stock_movement" (executeWorkflow -> ' + pgwId + ')');
  return [{ type: 'MISSING_STOCK_MOVEMENT_PATH', workflowName: wfName, message: wfName + ': Abbuch-Pfad unvollstaendig - fehlt: ' + missing.join(', '), severity: 'critical' }];
}
function buildDriftReport(opts) {
  const drifts = [];
  const liveIds = liveIdSet(opts.liveWorkflows);
  for (const rWf of opts.repoWorkflows) {
    const lWf = matchByName(rWf, opts.liveWorkflows);
    if (!lWf) continue;
    if (rWf.active === true && lWf.active === false) drifts.push({ type: 'WORKFLOW_DEACTIVATED', workflowName: rWf.name, message: '"' + rWf.name + '" im Repo aktiv, auf Mini deaktiviert', severity: 'critical' });
    drifts.push.apply(drifts, diffNodes(rWf.name, rWf.nodes || [], lWf.nodes || []));
    drifts.push.apply(drifts, checkWebhooks(rWf.name, rWf.nodes || [], lWf.nodes || []));
    drifts.push.apply(drifts, checkExecRefs(rWf.name, lWf.nodes || [], liveIds, opts.pgwWorkflowId));
    if (rWf.name.indexOf('WF3') === 0) drifts.push.apply(drifts, checkStockMovementPath(rWf.name, lWf.nodes || [], opts.pgwWorkflowId));
  }
  return { status: drifts.length > 0 ? 'drift' : 'ok', drifts };
}
// ──────────────────────────────────────────────────────────────────────

const PGW_ID = 'Sajezv8tJll0CLIv';
const REPO = 'PatrickM-git/automatenlager';
const EMAIL = 'PatrickZinke@gmx.net';

const liveResponse = $('HTTP Request - Get Live Workflows').first().json;
const liveWorkflows = liveResponse.data || [];

let dirData = await this.helpers.httpRequest({
  url: 'https://api.github.com/repos/' + REPO + '/contents',
  headers: { 'User-Agent': 'homelab-drift-check', 'Accept': 'application/vnd.github.v3+json' },
  json: true,
});
if (typeof dirData === 'string') { dirData = JSON.parse(dirData); }
const wfFiles = dirData.filter(function(f) { return f.type === 'file' && f.name.endsWith('.json') && f.name.startsWith('WF'); });

const repoWorkflows = [];
for (const file of wfFiles) {
  let wf = await this.helpers.httpRequest({ url: file.download_url, headers: { 'User-Agent': 'homelab-drift-check' }, json: true });
  if (typeof wf === 'string') { wf = JSON.parse(wf); }
  repoWorkflows.push(wf);
}

const report = buildDriftReport({ repoWorkflows, liveWorkflows, pgwWorkflowId: PGW_ID });

const day = new Date().toISOString().slice(0, 10);
let subject, html;
if (report.status === 'ok') {
  subject = 'WF-Drift-Check ' + day + ': ok';
  html = '<pre>WF-Drift-Check ' + day + ': kein Drift erkannt (' + repoWorkflows.length + ' Workflows gepr\u00fcft)</pre>';
} else {
  const critCount = report.drifts.filter(function(d) { return d.severity === 'critical'; }).length;
  subject = 'WF-Drift-Check ' + day + ': DRIFT \u2013 ' + report.drifts.length + ' Abweichungen (' + critCount + ' kritisch)';
  const lines = ['WF-Drift-Check ' + day + ': ' + report.drifts.length + ' Abweichungen', ''];
  for (const d of report.drifts) {
    lines.push('[' + d.severity.toUpperCase() + '] ' + d.type + ' \u2014 ' + d.workflowName);
    lines.push('  ' + d.message);
  }
  html = '<pre>' + lines.join('\n') + '</pre>';
}

return [{ json: { status: report.status, drifts: report.drifts, mail: { sendTo: EMAIL, subject, html }, shouldSendMail: report.status === 'drift', repoWfCount: repoWorkflows.length } }];
